		&lt;/tr&gt;
	&lt;/tbody&gt;
&lt;/table&gt;

&lt;p&gt;&amp;nbsp;&lt;/p&gt;

&lt;p&gt;(ii) P will not go with Q or R.&lt;/p&gt;

&lt;table border=&quot;1&quot; cellpadding=&quot;0&quot; cellspacing=&quot;0&quot; style=&quot;width:431px;&quot; width=&quot;431&quot;&gt;
	&lt;tbody&gt;
		&lt;tr&gt;
			&lt;td style=&quot;width:144px;height:38px;&quot;&gt;
			&lt;p align=&quot;center&quot;&gt;&lt;strong&gt;Commerce&lt;/strong&gt;&lt;/p&gt;
			&lt;/td&gt;
			&lt;td style=&quot;width:144px;height:38px;&quot;&gt;
			&lt;p align=&quot;center&quot;&gt;&lt;strong&gt;Science&lt;/strong&gt;&lt;/p&gt;
			&lt;/td&gt;
			&lt;td style=&quot;width:144px;height:38px;&quot;&gt;
			&lt;p align=&quot;center&quot;&gt;&lt;strong&gt;Art&lt;/strong&gt;&lt;/p&gt;
			&lt;/td&gt;
		&lt;/tr&gt;
		&lt;tr&gt;
			&lt;td style=&quot;width:144px;height:38px;&quot;&gt;
			&lt;p align=&quot;center&quot;&gt;A / B / C&lt;/p&gt;
			&lt;/td&gt;
			&lt;td style=&quot;width:144px;height:38px;&quot;&gt;
			&lt;p align=&quot;center&quot;&gt;P or (Q / R)&lt;/p&gt;
			&lt;/td&gt;
			&lt;td style=&quot;width:144px;height:38px;&quot;&gt;
			&lt;p align=&quot;center&quot;&gt;J / K / L&lt;/p&gt;
			&lt;/td&gt;
		&lt;/tr&gt;
	&lt;/tbody&gt;
&lt;/table&gt;

&lt;p&gt;&amp;nbsp;&lt;/p&gt;

&lt;p&gt;(iii) A and C will always go together.&lt;/p&gt;

&lt;table border=&quot;1&quot; cellpadding=&quot;0&quot; cellspacing=&quot;0&quot; style=&quot;width:431px;&quot; width=&quot;431&quot;&gt;
	&lt;tbody&gt;
		&lt;tr&gt;
			&lt;td style=&quot;width:144px;height:38px;&quot;&gt;
			&lt;p align=&quot;center&quot;&gt;&lt;strong&gt;Commerce&lt;/strong&gt;&lt;/p&gt;
			&lt;/td&gt;
			&lt;td style=&quot;width:144px;height:38px;&quot;&gt;
			&lt;p align=&quot;center&quot;&gt;&lt;strong&gt;Science&lt;/strong&gt;&lt;/p&gt;
