			<td style="width:144px;height:38px;">
			<p align="center"><strong>কমার্স</strong></p>
			</td>
			<td style="width:144px;height:38px;">
			<p align="center"><strong>বিজ্ঞান</strong></p>
			</td>
			<td style="width:144px;height:38px;">
			<p align="center"><strong>আর্ট</strong></p>
			</td>
		</tr>
		<tr>
			<td style="width:144px;height:38px;">
			<p align="center">A / B / C</p>
			</td>
			<td style="width:144px;height:38px;">
			<p align="center">P or (Q / R)</p>
			</td>
			<td style="width:144px;height:38px;">
			<p align="center">J / K / L</p>
			</td>
		</tr>
	</tbody>
</table>

<p>&nbsp;</p>

<p>(iii) A এবং C সর্বদা একসাথে যাবে।</p>

