			<p align="center"><strong>আর্ট</strong></p>
			</td>
		</tr>
		<tr>
			<td style="width:144px;height:38px;">
			<p align="center">B / (A + C)</p>
			</td>
			<td style="width:144px;height:38px;">
			<p align="center">P or (Q / R)</p>
			</td>
			<td style="width:144px;height:38px;">
			<p align="center">J / K / L</p>
			</td>
		</tr>
	</tbody>
</table>

<p>&nbsp;</p>

<p>(iv) K এবং L সর্বদা একসাথে যাবে।</p>

<table border="1" cellpadding="0" cellspacing="0" style="width:431px;" width="431">
	<tbody>
		<tr>
			<td style="width:144px;height:38px;">
			<p align="center"><strong>কমার্স</strong></p>
			</td>
			<td style="width:144px;height:38px;">
			<p align="center"><strong>বিজ্ঞান</strong></p>
			</td>
			<td style="width:144px;height:38px;">
			<p align="center"><strong>আর্ট</strong></p>
			</td>
		</tr>
		<tr>
			<td style="width:144px;height:38px;">
			<p align="center">B or (A + C)</p>
			</td>
			<td style="width:144px;height:38px;">
			<p align="center">P or (Q / R)</p>
			</td>
			<td style="width:144px;height:38px;">
			<p align="center">J or (K + L)</p>
			</td>
		</tr>
